import { useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';

import { updateRow } from '../../const/crud';
import { handleLogout } from '../../consts/handleLogout';

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function EditRoadSing() {
    const [road_id, setRoadID] = useState('');
    const [image, setFile] = useState('');
    const [latitude, setLatitude] = useState('');
    const [longitude, setLongitude] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();
    const { id } = useParams();

    const handelFileChange = (e) => {
        setFile(e.target.files[0]);
    };

    const submitRoadSing = async (e) => {
        const headers = {
            'Content-Type': 'multipart/form-data',
            'Accept': 'application/json'
        };
        const road_sing = { road_id, image, latitude, longitude };

        setLoading(true);
        e.preventDefault();
        updateRow('/roads/sings', id, road_sing, headers);
        setTimeout(() => {
            setRoadID('');
            setLatitude('');
            setLongitude('');
            navigate('/roads/sings');
        }, 5000);
        setLoading(false);
    };

    return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">Дорожное хозяйство</Link>
                    <div class="btn-group">
                        <button type="button" class="btn btn-info">{ localStorage.getItem('login') }</button>
                        <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                            <span class="visually-hidden">Переключатель выпадающего списка</span>
                        </button>
                        <ul class="dropdown-menu">
                            <li>
                                <a class="dropdown-item">
                                    <button
                                        onClick={() => { handleLogout(); navigate('/login') }}
                                        className='dropdown-item'
                                        disabled={loading}
                                    >
                                        {loading ? (
                                            <>
                                                <span className='spinner'></span>
                                                Выход...
                                            </>
                                        ) : 'Выйти'}
                                    </button>
                                </a>
                            </li>
                        </ul>
                    </div>
                </div>
            </nav>
            <form className='container' onSubmit={submitRoadSing}>
                <h1>Редактировнаие знака на дороге</h1>
                <div className='mb-3'>
                    <lable className='form-label'>ID дороги</lable>
                    <input 
                        type='text'
                        name='road_id' 
                        value={road_id.road_id} 
                        onChange={(e) => setRoadID(e.target.value)}
                        className='form-input'  
                        placeholder='road_id'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Изображение</lable>
                    <input 
                        type='file'
                        name='image'
                        accept='img/*' 
                        value={image.image} 
                        onChange={handelFileChange}
                        className='form-input'  
                        placeholder='image'
                        required  
                        multiple
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Широта</lable>
                    <input 
                        type='text'
                        name='latitude' 
                        value={latitude.latitude} 
                        onChange={(e) => setLatitude(e.target.value)}
                        className='form-input'  
                        placeholder='latitude'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Долгота</lable>
                    <input 
                        type='text'
                        name='longitude' 
                        value={longitude.longitude} 
                        onChange={(e) => setLongitude(e.target.value)}
                        className='form-input'  
                        placeholder='longitude'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Сохранить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/roads/sings')}
                >
                    Назад
                </button>
            </form>
        </div>
    )

};

export default EditRoadSing;
